/* 石睿_開場連動 — AU 開場白世界書連動腳本
   讀取第 0 條訊息各 swipe 的 metadata 註解，
   依當前 swipe 的 lore/exclude 批次開關世界書條目。
   所有 lore/exclude 為空時安靜 no-op。
   TavernHelper 不在時不報錯。
   26-07-10
   26-07-11 補強：事件監聽＋狀態指紋＋通知
   26-07-12 修寫入路徑：主走實戰驗證的 Lorebook API（setLorebookEntries，大梁承恩录同款）；
   新版 Worldbook API 僅作後備且 render 改用文件值 'immediate'（實案：render:false 後台不生效）；
   指紋改為寫入成功後才記錄（修「寫入失敗後同開場不重試」邊角）
   機制參考 yellows「开场白管理器(含世界书联动)」（Greeting Jumper V9.0，
   世界書開關代碼原致謝唐初稚老師），源：sssilvia27/st-scripts */

(function () {
  /* ── 0. 模組狀態 ──────────────────────────────── */
  var lastFingerprint = "";

  /* ── 1. 跨 scope 尋址工具 ─────────────────────── */
  function findApi(name) {
    var scopes = [window, window.parent, window.top];
    for (var i = 0; i < scopes.length; i++) {
      try { if (typeof scopes[i][name] === "function") return scopes[i][name]; }
      catch (_) { /* cross-origin, skip */ }
    }
    return null;
  }

  function findGlobal(name) {
    var scopes = [window, window.parent, window.top];
    for (var i = 0; i < scopes.length; i++) {
      try { if (scopes[i][name] != null) return scopes[i][name]; }
      catch (_) { /* cross-origin, skip */ }
    }
    return null;
  }

  /* ── 2. 主同步函式 ─────────────────────────────── */
  async function syncGreetingLore() {
    var getChatMessages = findApi("getChatMessages");
    if (!getChatMessages) {
      console.warn("[石睿_開場連動] TavernHelper API 不可用，跳過");
      return;
    }

    /* ── 取第 0 條訊息（含 swipes）──────────── */
    var msgs;
    try { msgs = await getChatMessages(0, { include_swipes: true }); }
    catch (_) { console.warn("[石睿_開場連動] 無法取得訊息"); return; }

    if (!msgs || !msgs.length) return;
    var msg0 = msgs[0];
    var swipes = msg0.swipes || [msg0.mes || ""];

    /* ── 解析所有 swipe 的 metadata ─────────── */
    var RE_META = /<!--\s*(title|desc|type|lore|exclude)\s*:\s*(.*?)\s*-->/g;

    function parseMeta(text) {
      var meta = { title: "", desc: "", type: "", lore: [], exclude: [] };
      if (!text) return meta;
      var m;
      RE_META.lastIndex = 0;
      while ((m = RE_META.exec(text)) !== null) {
        var key = m[1];
        var val = m[2].trim();
        if (key === "lore" || key === "exclude") {
          meta[key] = val ? val.split(",").map(function (s) { return s.trim(); }).filter(Boolean) : [];
        } else {
          meta[key] = val;
        }
      }
      return meta;
    }

    var allMeta = swipes.map(function (s) { return parseMeta(s); });

    /* ── 收集所有 swipe 提及的 UID（managed set）＋預設開關映射 ──
       lore 清單裡的 UID ＝ AU 專屬條目，出廠預設關（只在被 lore 點名時才開）
       exclude 清單裡的 UID ＝ 主線常規內容，出廠預設開（exclude 的用途是暫時關掉平時開著的東西）
       同一 UID 若同時出現在某些 swipe 的 lore 與另一些的 exclude，以 exclude 類優先（視為預設開） */
    var managed  = {};
    var defaultOn = {};
    allMeta.forEach(function (m) {
      m.lore.forEach(function (uid)    { managed[uid] = true; });
      m.exclude.forEach(function (uid) { managed[uid] = true; defaultOn[uid] = true; });
    });

    if (Object.keys(managed).length === 0) return;

    /* ── 當前 swipe 的 lore / exclude ────────── */
    var currentIdx = msg0.swipe_id || 0;
    if (currentIdx < 0 || currentIdx >= allMeta.length) currentIdx = 0;
    var current = allMeta[currentIdx];

    /* ── 狀態指紋：與上次「成功寫入」相同就跳過 ── */
    var fp = currentIdx + ":inc=" + current.lore.slice().sort().join(",") + ";exc=" + current.exclude.slice().sort().join(",");
    if (fp === lastFingerprint) return;

    var enableSet  = {};
    var disableSet = {};
    current.lore.forEach(function (uid)    { enableSet[uid]  = true; });
    current.exclude.forEach(function (uid) { disableSet[uid] = true; });

    /* 三分支語義（defaultOn）：lore 點名→開；exclude 點名→關；受管未點名→恢復出廠 */
    function desiredState(uid) {
      if (enableSet[uid]) return true;
      if (disableSet[uid]) return false;
      return !!defaultOn[uid];
    }

    /* ── 取世界書名稱 ──────────────────────── */
    var TH = findGlobal("TavernHelper");
    var wbName = null;
    try {
      if (TH && typeof TH.getCurrentCharPrimaryLorebook === "function") {
        wbName = await TH.getCurrentCharPrimaryLorebook();
      }
    } catch (_) { /* fallthrough */ }
    if (!wbName) {
      var getNames = findApi("getCharWorldbookNames");
      if (getNames) {
        try { var names = await getNames("current"); wbName = (names && names.primary) || null; }
        catch (_) { /* fallthrough */ }
      }
    }
    if (!wbName) {
      console.warn("[石睿_開場連動] 角色無嵌入世界書，跳過");
      return;
    }

    /* ── 寫入：主走實戰驗證的 Lorebook API，後備走新版 Worldbook API ── */
    var actionLogs = [];
    var wrote = false;

    try {
      if (TH && typeof TH.getLorebookEntries === "function" && typeof TH.setLorebookEntries === "function") {
        var entries = await TH.getLorebookEntries(wbName);
        var updates = [];
        (entries || []).forEach(function (entry) {
          var uid = String(entry.uid);
          if (!managed[uid]) return;
          var want = desiredState(uid);
          var cur = entry.enabled === true;
          if (cur !== want) {
            updates.push({ uid: entry.uid, enabled: want });
            var entryName = entry.comment || entry.name || ("UID:" + uid);
            actionLogs.push((want ? "✅" : "🚫") + " " + entryName);
          }
        });
        if (updates.length > 0) await TH.setLorebookEntries(wbName, updates);
        wrote = true;
      } else {
        var updateWorldbookWith = findApi("updateWorldbookWith");
        if (!updateWorldbookWith) { console.warn("[石睿_開場連動] 世界書寫入 API 不可用，跳過"); return; }
        await updateWorldbookWith(wbName, function (list) {
          list.forEach(function (entry) {
            var uid = String(entry.uid);
            if (!managed[uid]) return;
            var want = desiredState(uid);
            if (entry.enabled !== want) {
              var entryName = entry.comment || entry.name || ("UID:" + uid);
              actionLogs.push((want ? "✅" : "🚫") + " " + entryName);
            }
            entry.enabled = want;
          });
          return list;
        }, { render: "immediate" });
        wrote = true;
      }
    } catch (_) {
      console.warn("[石睿_開場連動] 更新世界書失敗（本次不記指紋，下次事件會重試）");
      return;
    }

    if (wrote) lastFingerprint = fp;

    /* ── 通知 ──────────────────────────────────── */
    if (actionLogs.length > 0) {
      var _toastr = findGlobal("toastr");
      if (_toastr && typeof _toastr.info === "function") {
        if (actionLogs.length > 3) {
          _toastr.info("已同步 " + actionLogs.length + " 個世界書條目", "後台世界書同步", { timeOut: 2000, preventDuplicates: true });
        } else {
          _toastr.info(actionLogs.join("<br>"), "後台世界書同步", { timeOut: 2000, preventDuplicates: true, escapeHtml: false });
        }
      } else {
        console.log("[石睿_開場連動] 同步結果：" + actionLogs.join(", "));
      }
    }
  }

  /* ── 3. 事件掛載（輪詢等待 eventOn/tavern_events 就緒）─── */
  (async function () {
    var attempts = 0;
    var maxAttempts = 20; /* 500ms * 20 = 10 秒 */

    while (attempts < maxAttempts) {
      var eo = findApi("eventOn");
      var te = findGlobal("tavern_events");
      if (eo && te) {
        eo(te.CHARACTER_MESSAGE_RENDERED, function (msgId) {
          if (Number(msgId) === 0) syncGreetingLore();
        });
        eo(te.MESSAGE_SWIPED, function (msgId) {
          if (Number(msgId) === 0) syncGreetingLore();
        });
        eo(te.CHAT_CHANGED, function () {
          lastFingerprint = "";
          syncGreetingLore();
        });
        console.log("[石睿_開場連動] 事件監聽已掛載");
        syncGreetingLore(); /* 首載立即同步一次 */
        return;
      }
      await new Promise(function (r) { setTimeout(r, 500); });
      attempts++;
    }

    /* 逾時 fallback：直接跑一次，等效改前行為 */
    console.warn("[石睿_開場連動] eventOn/tavern_events 10 秒內未就緒，fallback 直接執行");
    syncGreetingLore();
  })();
})();
